     2→ * Completion-time social action verification.
     3→ * Confirms user actually performed the task (follow, like, repost, post, join, etc.)
     4→ * Separate from social-validator.ts which only checks target existence at creation time.
     5→ */
     6→import { PrismaClient } from '@prisma/client'
     7→import { extractTweetId, normaliseHandle } from '../x/x-utils'
     8→import { getTweetInfo, checkRetweet, checkFollow } from '../x/x-twitter-api45-client'
     9→import { getGuildMember, getUserGuildMember, resolveInvite } from '../discord/discord-rest-client'
    10→import { validateSocialTarget, type SocialValidationResult } from './social-validator'
    11→
    12→export interface VerificationContext {
    13→  userId: string
    14→  prisma: PrismaClient
    15→  // X identity
    16→  xId?: string | null
    17→  xHandle?: string | null
    18→  xAccessToken?: string | null
    19→  xRefreshToken?: string | null
    20→  xTokenExpiry?: Date | null
    21→  // Discord identity
    22→  discordId?: string | null
    23→  discordAccessToken?: string | null
    24→  discordTokenExpiry?: Date | null
    25→  // Telegram identity
    26→  telegramId?: string | null
    27→  // Proof URLs for post/quote_post (map of taskIndex → URL)
    28→  proofUrls?: Record<number, string>
    29→  // Task params from quest definition
    30→  params?: Record<string, string>
    31→  // Telegram bot token
    32→  telegramBotToken?: string
    33→}
    34→
    35→// ── X Verification ──────────────────────────────────────────────
    36→
    37→async function verifyXAction(
    38→  actionType: string, ctx: VerificationContext, taskIndex: number,
    39→): Promise<SocialValidationResult> {
    40→  // Support multiple param key conventions used by quest creators
    41→  const targetValue = ctx.params?.targetUrl || ctx.params?.postUrl || ctx.params?.accountHandle || ctx.params?.username || ''
    42→
    43→  switch (actionType) {
    44→    case 'post':
    45→    case 'quote_post': {
    46→      const proofUrl = ctx.proofUrls?.[taskIndex]
    47→      if (!proofUrl) return { valid: false, error: 'Paste your tweet URL to verify' }
    48→      const proofTweetId = extractTweetId(proofUrl)
    49→      if (!proofTweetId) return { valid: false, error: 'Invalid tweet URL — use format: https://x.com/.../status/...' }
    50→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    51→
    52→      const tweet = await getTweetInfo(proofTweetId)
    53→      if (!tweet) return { valid: false, error: 'Tweet not found — is it public?' }
    54→
    55→      if (normaliseHandle(tweet.authorScreenName) !== normaliseHandle(ctx.xHandle)) {
    56→        return { valid: false, error: 'This tweet was not posted by your linked X account' }
    57→      }
    58→
    59→      if (actionType === 'quote_post') {
    60→        const targetTweetId = extractTweetId(targetValue)
    61→        if (targetTweetId) {
    62→          const quoteOk =
    63→            tweet.quotedTweetId === targetTweetId ||
    64→            tweet.entityUrls.some(u => u.includes(targetTweetId)) ||
    65→            tweet.text.includes(targetTweetId)
    66→          if (!quoteOk) return { valid: false, error: 'This tweet does not quote the required post' }
    67→        }
    68→      }
    69→      return { valid: true }
    70→    }
    71→
    72→    case 'follow_account': {
    73→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    74→      const targetHandle = targetValue.replace(/^@/, '').replace(/^https?:\/\/(x|twitter)\.com\//, '').split('/')[0]
    75→      if (!targetHandle) return { valid: false, error: 'Quest task missing target account — contact quest creator' }
    76→
    77→      const follows = await checkFollow(ctx.xHandle, targetHandle)
    78→      if (follows === null) return { valid: false, error: 'Follow verification unavailable — try again later' }
    79→      return follows ? { valid: true } : { valid: false, error: 'not following this account' }
    80→    }
    81→
    82→    case 'repost': {
    83→      if (!ctx.xHandle) return { valid: false, error: 'Link your X account to verify this task' }
    84→      const tweetId = extractTweetId(targetValue) || targetValue
    85→      if (!tweetId) return { valid: false, error: 'Quest task missing tweet URL — contact quest creator' }
    86→
    87→      const retweeted = await checkRetweet(ctx.xHandle, tweetId)
    88→      if (retweeted === null) return { valid: false, error: 'Repost verification unavailable — try again later' }
    89→      return retweeted ? { valid: true } : { valid: false, error: 'You have not reposted this tweet' }
    90→    }
    91→
    92→    case 'like_post':
    93→      // Like verification not supported via this API — auto-pass
    94→      return { valid: true }
    95→
    96→    default:
    97→      return { valid: true }
    98→  }
    99→}
   100→
   101→// ── Discord Verification ────────────────────────────────────────
   102→
   103→async function verifyDiscordAction(
   104→  actionType: string, ctx: VerificationContext,
   105→): Promise<SocialValidationResult> {
   106→  if (!ctx.discordId) return { valid: false, error: 'Link your Discord account to verify this task' }
   107→
   108→  if (actionType === 'join_server') {
   109→    let guildId = ctx.params?.guildId
   110→    // Fallback: resolve inviteUrl → guildId (handles legacy quests or when createQuest/updateQuest did not resolve)
   111→    if (!guildId && ctx.params?.inviteUrl) {
   112→      const code = ctx.params.inviteUrl.replace(/^https?:\/\/(discord\.gg|discord\.com\/invite)\//i, '').trim()
   113→      if (code) {
   114→        const guild = await resolveInvite(code)
   115→        if (guild) guildId = guild.guildId
   116→      }
   117→    }
   118→    if (!guildId) return { valid: false, error: 'Quest task missing guildId — contact quest creator' }
   119→
   120→    // Prefer OAuth user token (no bot needed)
   121→    if (ctx.discordAccessToken) {
   122→      const roles = await getUserGuildMember(ctx.discordAccessToken, guildId)
   123→      if (roles !== null) return { valid: true }
   124→    }
   125→    // Fallback to bot
   126→    const botRoles = await getGuildMember(guildId, ctx.discordId)
   127→    if (botRoles !== null) return { valid: true }
   128→
   129→    // If token is absent or expired, give a more helpful error
   130→    const hasValidToken = ctx.discordAccessToken && (
   131→      !ctx.discordTokenExpiry || ctx.discordTokenExpiry > new Date()
   132→    )
   133→    if (!hasValidToken) {
   134→      return { valid: false, error: 'Discord access expired — re-link Discord in Settings, then verify again' }
   135→    }
   136→    return { valid: false, error: 'You have not joined this Discord server' }
   137→  }
   138→
   139→  // verify_role: delegate to existing validateDiscordRole via validateSocialTarget
   140→  if (actionType === 'verify_role') {
   141→    return validateSocialTarget('discord', 'verify_role', '', undefined, {
   142→      discordId: ctx.discordId,
   143→      discordAccessToken: ctx.discordAccessToken,
   144→      params: ctx.params,
   145→    })
   146→  }
   147→
   148→  return { valid: true }
   149→}
   150→
   151→// ── Telegram Verification ───────────────────────────────────────
   152→
   153→async function verifyTelegramAction(
   154→  actionType: string, ctx: VerificationContext,
   155→): Promise<SocialValidationResult> {
   156→  if (actionType !== 'join_channel') return { valid: true }
   157→  if (!ctx.telegramId) return { valid: false, error: 'Link your Telegram account to verify this task' }
   158→  if (!ctx.telegramBotToken) return { valid: false, error: 'Telegram verification unavailable' }
   159→
   160→  const channelUrl = ctx.params?.channelUrl || ctx.params?.targetUrl || ''
   161→  let chatId: string
   162→  const urlMatch = channelUrl.match(/t\.me\/([A-Za-z0-9_]+)/)
   163→  if (urlMatch) chatId = `@${urlMatch[1]}`
   164→  else if (channelUrl.startsWith('@')) chatId = channelUrl
   165→  else chatId = `@${channelUrl.replace(/^https?:\/\//, '')}`
   166→
   167→  try {
   168→    const res = await fetch(
   169→      `https://api.telegram.org/bot${ctx.telegramBotToken}/getChatMember?chat_id=${encodeURIComponent(chatId)}&user_id=${ctx.telegramId}`,
   170→      { signal: AbortSignal.timeout(8000) },
   171→    )
   172→
   173→    // Always parse body — Telegram always returns JSON even for HTTP errors
   174→    const data = await res.json() as { ok: boolean; result?: { status: string }; description?: string; error_code?: number }
   175→
   176→    if (!data.ok) {
   177→      const desc = data.description ?? ''
   178→      console.error(`[Telegram] getChatMember failed for chatId=${chatId} userId=${ctx.telegramId}: ${res.status} ${desc}`)
   179→
   180→      if (desc.includes('CHAT_ADMIN_REQUIRED') || res.status === 403)
   181→        return { valid: false, error: 'Bot must be added as an admin of this channel' }
   182→      if (desc.includes('chat not found'))
   183→        return { valid: false, error: 'Channel not found — verify the channel URL in the quest task' }
   184→      if (desc.includes('USER_ID_INVALID') || desc.includes('user not found'))
   185→        return { valid: false, error: 'Could not verify your Telegram account — try unlinking and relinking' }
   186→
   187→      return { valid: false, error: `Telegram error: ${desc || 'Could not check membership'}` }
   188→    }
   189→
   190→    const joined = ['creator', 'administrator', 'member', 'restricted'].includes(data.result?.status ?? '')
   191→    return joined
   192→      ? { valid: true }
   193→      : { valid: false, error: 'You have not joined this channel' }
   194→  } catch {
   195→    return { valid: false, error: 'Telegram API unavailable — try again later' }
   196→  }
   197→}
   198→
   199→// ── Main Dispatcher ─────────────────────────────────────────────
   200→
   201→/** Completion-time verification: did user actually perform this action? */
   202→export async function verifySocialAction(
   203→  platform: string, actionType: string, taskIndex: number, ctx: VerificationContext,
   204→): Promise<SocialValidationResult> {
   205→  switch (platform) {
   206→    case 'x': return verifyXAction(actionType, ctx, taskIndex)
   207→    case 'discord': return verifyDiscordAction(actionType, ctx)
   208→    case 'telegram': return verifyTelegramAction(actionType, ctx)
   209→    default: return { valid: true }
   210→  }
   211→}
